/**
 * llama2_int8_gemmini.c - Int8 Quantized LLM Inference (Gemmini Accelerated)
 *
 * Loads int8 weight files generated by quantize.py
 * Uses Gemmini systolic array to accelerate matrix multiplication
 *
 * Usage:
 *   ./llama2_int8_gemmini stories15M_int8.bin -n 64 -i "Once upon a time"
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <math.h>
#include <fcntl.h>
#include <unistd.h>

#include "include/gemmini.h"

// Use rdtime to get time
static inline uint64_t get_cycles() {
    uint64_t time;
    asm volatile ("rdtime %0" : "=r" (time));
    return time;
}

// ----------------------------------------------------------------------------
// Profiling struct

typedef struct {
    // Cumulative time for each stage (inside forward)
    uint64_t embedding;       // token embedding lookup
    uint64_t rmsnorm_att;     // attention RMSNorm
    uint64_t rmsnorm_ffn;     // FFN RMSNorm
    uint64_t rmsnorm_final;   // final RMSNorm
    uint64_t qkv_proj;        // Q, K, V projection (3 matmuls)
    uint64_t rope;            // RoPE positional encoding
    uint64_t attention;       // multi-head attention (QK^T + softmax + V)
    uint64_t wo_proj;         // output projection
    uint64_t ffn_w1w3;        // FFN W1 and W3 (2 matmuls)
    uint64_t ffn_silu;        // SiLU activation
    uint64_t ffn_w2;          // FFN W2 projection
    uint64_t residual;        // residual connection
    uint64_t classifier;      // final classifier matmul
    
    // Overhead in the generation loop (outside forward)
    uint64_t temp_scaling;    // temperature scaling (32000 divisions)
    uint64_t softmax_logits;  // softmax on logits (32000 exp calls!)
    uint64_t sampling;        // token sampling
    uint64_t decode_print;    // tokenizer decode + printf
    
    // matmul internal breakdown
    uint64_t matmul_quantize;    // input quantization time
    uint64_t matmul_gemmini;     // Gemmini computation time
    uint64_t matmul_dequantize;  // output dequantization time
    
    // Statistics
    int total_tokens;
    int total_matmuls;
} ProfileStats;

static ProfileStats g_profile = {0};

// Profiling switch (can be disabled at compile time)
#ifndef ENABLE_PROFILING
#define ENABLE_PROFILING 1
#endif

#if ENABLE_PROFILING
static uint64_t _profile_tmp_start;
#define PROFILE_START() _profile_tmp_start = get_cycles()
#define PROFILE_END(field) g_profile.field += (get_cycles() - _profile_tmp_start)
#else
#define PROFILE_START() ((void)0)
#define PROFILE_END(field) ((void)0)
#endif

// ----------------------------------------------------------------------------
// Model configuration

typedef struct {
    int dim;
    int hidden_dim;
    int n_layers;
    int n_heads;
    int n_kv_heads;
    int vocab_size;
    int seq_len;
} Config;

typedef struct {
    float* token_embedding_table;  // float32, used for lookup
    int8_t* token_embedding_int8;  // int8, used for classifier
    float embedding_scale;         // quantization scale for embedding
    
    float* rms_att_weight;
    float* rms_ffn_weight;
    float* rms_final_weight;
    
    int8_t** wq;
    int8_t** wk;
    int8_t** wv;
    int8_t** wo;
    int8_t** w1;
    int8_t** w2;
    int8_t** w3;
    
    float** w_scales;
    
    float* act_xb;
    float* act_q;
    float* act_k;
    float* act_v;
    float* act_xb_attn;
    float* act_xb_ffn;
    float* act_hb;
    float* act_hb2;
    float* act_hb_silu;
    float act_x_final;
    float act_logits;
    
    int shared_weights;
} QuantizedWeights;

typedef struct {
    float *x, *xb, *xb2, *hb, *hb2;
    float *q, *k, *v, *att;
    float *logits;
    float *key_cache, *value_cache;
} RunState;

// ----------------------------------------------------------------------------
// Gemmini Int8 matrix multiplication
//
// Computes: out(d,1) = W(d,n) @ x(n,1)
// W is int8, x is float (needs quantization)
// Output is float

// Gemmini buffers
static elem_t *g_A = NULL;  // weights (already int8)
static elem_t *g_B = NULL;  // input (after quantization)
static elem_t *g_C = NULL;  // output (int8)
static size_t g_A_size = 0, g_B_size = 0, g_C_size = 0;

static void ensure_gemmini_buffers(size_t a_sz, size_t b_sz, size_t c_sz) {
    if (b_sz > g_B_size) {
        free(g_B);
        g_B = (elem_t*)malloc(b_sz);
        g_B_size = b_sz;
    }
    if (c_sz > g_C_size) {
        free(g_C);
        g_C = (elem_t*)malloc(c_sz);
        g_C_size = c_sz;
    }
}

// Statistics
static int gemmini_calls = 0;
static int cpu_calls = 0;

// Debug switch: set to 1 to force CPU, set to 0 to use Gemmini
#ifndef USE_CPU_ONLY
#define USE_CPU_ONLY 0
#endif

static void cpu_matmul_int8(float* xout, float* x, int8_t* w, 
                             float w_scale, float x_scale, int n, int d) {
    int8_t* x_q = (int8_t*)malloc(n);
    for (int i = 0; i < n; i++) {
        int32_t q = (int32_t)roundf(x[i] / x_scale);
        x_q[i] = (q > 127) ? 127 : ((q < -128) ? -128 : q);
    }
    float scale = w_scale * x_scale;
    for (int i = 0; i < d; i++) {
        int32_t acc = 0;
        for (int j = 0; j < n; j++) {
            acc += (int32_t)w[i * n + j] * (int32_t)x_q[j];
        }
        xout[i] = (float)acc * scale;
    }
    free(x_q);
}

void matmul_gemmini(float* xout, float* x, int8_t* w, 
                    float w_scale, float x_scale, float out_scale,
                    int n, int d) {
    // Force CPU or use CPU for small matrices
    if (USE_CPU_ONLY || n < 16 || d < 16) {
        cpu_calls++;
        cpu_matmul_int8(xout, x, w, w_scale, x_scale, n, d);
        return;
    }
    
    gemmini_calls++;
    g_profile.total_matmuls++;
    ensure_gemmini_buffers(0, n, d);
    
    // 1. Quantize input
    PROFILE_START();
    for (int i = 0; i < n; i++) {
        int32_t q = (int32_t)roundf(x[i] / x_scale);
        g_B[i] = (q > 127) ? 127 : ((q < -128) ? -128 : q);
    }
    PROFILE_END(matmul_quantize);
    
    // 2. Compute acc_scale
    float acc_scale_f = (w_scale * x_scale) / out_scale;
    scale_t acc_scale = (scale_t)acc_scale_f;
    
    // 3. Gemmini computation
    PROFILE_START();
    tiled_matmul_auto(
        d, 1, n,
        (elem_t*)w, g_B,
        NULL, g_C,
        n, 1, 0, 1,
        MVIN_SCALE_IDENTITY,
        MVIN_SCALE_IDENTITY,
        MVIN_SCALE_IDENTITY,
        NO_ACTIVATION,
        acc_scale,
        0,
        false,
        false, false,
        false, false,
        0, WS
    );
    gemmini_fence();
    PROFILE_END(matmul_gemmini);
    
    // 4. Dequantize
    PROFILE_START();
    for (int i = 0; i < d; i++) {
        xout[i] = (float)((int8_t)g_C[i]) * out_scale;
    }
    PROFILE_END(matmul_dequantize);
}

// ----------------------------------------------------------------------------
// Neural network operations

void rmsnorm(float* o, float* x, float* weight, int size) {
    float ss = 0.0f;
    for (int j = 0; j < size; j++) ss += x[j] * x[j];
    ss /= size;
    ss = 1.0f / sqrtf(ss + 1e-5f);
    for (int j = 0; j < size; j++) o[j] = weight[j] * (ss * x[j]);
}

void softmax(float* x, int size) {
    float max_val = x[0];
    for (int i = 1; i < size; i++) if (x[i] > max_val) max_val = x[i];
    float sum = 0.0f;
    for (int i = 0; i < size; i++) { x[i] = expf(x[i] - max_val); sum += x[i]; }
    for (int i = 0; i < size; i++) x[i] /= sum;
}

// ----------------------------------------------------------------------------
// Transformer forward pass (Gemmini Int8)

float* forward(int token, int pos, Config* p, QuantizedWeights* w, RunState* s) {
    float *x = s->x;
    int dim = p->dim;
    int kv_dim = (p->dim * p->n_kv_heads) / p->n_heads;
    int kv_mul = p->n_heads / p->n_kv_heads;
    int hidden_dim = p->hidden_dim;
    int head_size = dim / p->n_heads;

    g_profile.total_tokens++;

    // Token embedding
    PROFILE_START();
    float* content_row = w->token_embedding_table + token * dim;
    memcpy(x, content_row, dim * sizeof(float));
    PROFILE_END(embedding);

    for (int l = 0; l < p->n_layers; l++) {
        // Attention RMSNorm
        PROFILE_START();
        rmsnorm(s->xb, x, w->rms_att_weight + l * dim, dim);
        PROFILE_END(rmsnorm_att);

        int loff = l * p->seq_len * kv_dim;
        s->k = s->key_cache + loff + pos * kv_dim;
        s->v = s->value_cache + loff + pos * kv_dim;

        // QKV projection (Gemmini Int8)
        PROFILE_START();
        matmul_gemmini(s->q, s->xb, w->wq[l], w->w_scales[l][0], w->act_xb[l], w->act_q[l], dim, dim);
        matmul_gemmini(s->k, s->xb, w->wk[l], w->w_scales[l][1], w->act_xb[l], w->act_k[l], dim, kv_dim);
        matmul_gemmini(s->v, s->xb, w->wv[l], w->w_scales[l][2], w->act_xb[l], w->act_v[l], dim, kv_dim);
        PROFILE_END(qkv_proj);

        // RoPE
        PROFILE_START();
        for (int i = 0; i < dim; i += 2) {
            int head_dim = i % head_size;
            float freq = 1.0f / powf(10000.0f, head_dim / (float)head_size);
            float val = pos * freq;
            float fcr = cosf(val), fci = sinf(val);
            int rotn = i < kv_dim ? 2 : 1;
            for (int v = 0; v < rotn; v++) {
                float* vec = v == 0 ? s->q : s->k;
                float v0 = vec[i], v1 = vec[i + 1];
                vec[i] = v0 * fcr - v1 * fci;
                vec[i + 1] = v0 * fci + v1 * fcr;
            }
        }
        PROFILE_END(rope);

        // Multi-head attention (CPU, since it is a sparse operation)
        PROFILE_START();
        memset(s->xb, 0, dim * sizeof(float));
        for (int h = 0; h < p->n_heads; h++) {
            float* q = s->q + h * head_size;
            float* att = s->att + h * p->seq_len;
            
            for (int t = 0; t <= pos; t++) {
                float* k = s->key_cache + loff + t * kv_dim + (h / kv_mul) * head_size;
                float score = 0.0f;
                for (int i = 0; i < head_size; i++) score += q[i] * k[i];
                score /= sqrtf(head_size);
                att[t] = score;
            }

            softmax(att, pos + 1);

            float* xb = s->xb + h * head_size;
            for (int t = 0; t <= pos; t++) {
                float* v = s->value_cache + loff + t * kv_dim + (h / kv_mul) * head_size;
                float a = att[t];
                for (int i = 0; i < head_size; i++) xb[i] += a * v[i];
            }
        }
        PROFILE_END(attention);

        // Output projection (Gemmini Int8)
        PROFILE_START();
        matmul_gemmini(s->xb2, s->xb, w->wo[l], w->w_scales[l][3], w->act_xb_attn[l], w->act_xb[l], dim, dim);
        PROFILE_END(wo_proj);

        // Residual connection
        PROFILE_START();
        for (int i = 0; i < dim; i++) x[i] += s->xb2[i];
        PROFILE_END(residual);

        // FFN RMSNorm
        PROFILE_START();
        rmsnorm(s->xb, x, w->rms_ffn_weight + l * dim, dim);
        PROFILE_END(rmsnorm_ffn);

        // FFN W1, W3 (Gemmini Int8)
        PROFILE_START();
        matmul_gemmini(s->hb, s->xb, w->w1[l], w->w_scales[l][4], w->act_xb_ffn[l], w->act_hb[l], dim, hidden_dim);
        matmul_gemmini(s->hb2, s->xb, w->w3[l], w->w_scales[l][6], w->act_xb_ffn[l], w->act_hb2[l], dim, hidden_dim);
        PROFILE_END(ffn_w1w3);

        // SiLU
        PROFILE_START();
        for (int i = 0; i < hidden_dim; i++) {
            float val = s->hb[i];
            val *= (1.0f / (1.0f + expf(-val)));
            s->hb[i] = val * s->hb2[i];
        }
        PROFILE_END(ffn_silu);

        // W2 projection (Gemmini Int8)
        PROFILE_START();
        matmul_gemmini(s->xb, s->hb, w->w2[l], w->w_scales[l][5], w->act_hb_silu[l], w->act_xb_ffn[l], hidden_dim, dim);
        PROFILE_END(ffn_w2);

        // Residual connection
        PROFILE_START();
        for (int i = 0; i < dim; i++) x[i] += s->xb[i];
        PROFILE_END(residual);
    }

    // Final RMSNorm
    PROFILE_START();
    rmsnorm(x, x, w->rms_final_weight, dim);
    PROFILE_END(rmsnorm_final);

    // Classifier (Gemmini Int8!)
    // logits(vocab_size) = embedding(vocab_size x dim) @ x(dim)
    PROFILE_START();
    matmul_gemmini(s->logits, x, w->token_embedding_int8, 
                   w->embedding_scale, w->act_x_final, w->act_logits,
                   dim, p->vocab_size);
    PROFILE_END(classifier);

    return s->logits;
}

// ----------------------------------------------------------------------------
// Tokenizer

typedef struct { char *str; int id; } TokenIndex;
typedef struct {
    char** vocab;
    float* vocab_scores;
    TokenIndex *sorted_vocab;
    int vocab_size;
    unsigned int max_token_length;
    unsigned char byte_pieces[512];
} Tokenizer;

int compare_tokens(const void *a, const void *b) {
    return strcmp(((TokenIndex*)a)->str, ((TokenIndex*)b)->str);
}

void build_tokenizer(Tokenizer* t, char* tokenizer_path, int vocab_size) {
    t->vocab_size = vocab_size;
    t->vocab = (char**)malloc(vocab_size * sizeof(char*));
    t->vocab_scores = (float*)malloc(vocab_size * sizeof(float));
    t->sorted_vocab = NULL;
    for (int i = 0; i < 256; i++) {
        t->byte_pieces[i * 2] = (unsigned char)i;
        t->byte_pieces[i * 2 + 1] = '\0';
    }
    FILE *file = fopen(tokenizer_path, "rb");
    if (!file) { fprintf(stderr, "Cannot open tokenizer: %s\n", tokenizer_path); exit(1); }
    fread(&t->max_token_length, sizeof(int), 1, file);
    int len;
    for (int i = 0; i < vocab_size; i++) {
        fread(t->vocab_scores + i, sizeof(float), 1, file);
        fread(&len, sizeof(int), 1, file);
        t->vocab[i] = (char *)malloc(len + 1);
        fread(t->vocab[i], len, 1, file);
        t->vocab[i][len] = '\0';
    }
    fclose(file);
    t->sorted_vocab = malloc(vocab_size * sizeof(TokenIndex));
    for (int i = 0; i < vocab_size; i++) {
        t->sorted_vocab[i].str = t->vocab[i];
        t->sorted_vocab[i].id = i;
    }
    qsort(t->sorted_vocab, vocab_size, sizeof(TokenIndex), compare_tokens);
}

char* decode(Tokenizer* t, int prev_token, int token) {
    char *piece = t->vocab[token];
    if (prev_token == 1 && piece[0] == ' ') piece++;
    unsigned char byte_val;
    if (sscanf(piece, "<0x%02hhX>", &byte_val) == 1)
        piece = (char*)t->byte_pieces + byte_val * 2;
    return piece;
}

int str_lookup(char *str, TokenIndex *sorted_vocab, int vocab_size) {
    TokenIndex tok = { .str = str };
    TokenIndex *res = bsearch(&tok, sorted_vocab, vocab_size, sizeof(TokenIndex), compare_tokens);
    return res ? res->id : -1;
}

void encode(Tokenizer* t, char *text, int8_t bos, int8_t eos, int *tokens, int *n_tokens) {
    *n_tokens = 0;
    if (bos) tokens[(*n_tokens)++] = 1;
    if (text && *text) {
        int dummy = str_lookup(" ", t->sorted_vocab, t->vocab_size);
        tokens[(*n_tokens)++] = dummy;
    }
    char* buf = malloc(t->max_token_length * 2 + 3);
    for (char *c = text; c && *c; c++) {
        if ((*c & 0xC0) != 0x80) { buf[0] = *c; buf[1] = '\0'; }
        int id = str_lookup(buf, t->sorted_vocab, t->vocab_size);
        if (id != -1) tokens[(*n_tokens)++] = id;
        else for (int i = 0; buf[i]; i++) tokens[(*n_tokens)++] = (unsigned char)buf[i] + 3;
    }
    free(buf);
    while (1) {
        float best_score = -1e10; int best_id = -1, best_idx = -1;
        char* buf = malloc(t->max_token_length * 2 + 3);
        for (int i = 0; i < *n_tokens - 1; i++) {
            sprintf(buf, "%s%s", t->vocab[tokens[i]], t->vocab[tokens[i+1]]);
            int id = str_lookup(buf, t->sorted_vocab, t->vocab_size);
            if (id != -1 && t->vocab_scores[id] > best_score) {
                best_score = t->vocab_scores[id]; best_id = id; best_idx = i;
            }
        }
        free(buf);
        if (best_idx == -1) break;
        tokens[best_idx] = best_id;
        for (int i = best_idx + 1; i < *n_tokens - 1; i++) tokens[i] = tokens[i+1];
        (*n_tokens)--;
    }
    if (eos) tokens[(*n_tokens)++] = 2;
}

// ----------------------------------------------------------------------------
// Sampler

int sample_argmax(float* probs, int n) {
    int max_i = 0;
    float max_p = probs[0];
    for (int i = 1; i < n; i++) if (probs[i] > max_p) { max_i = i; max_p = probs[i]; }
    return max_i;
}

unsigned int random_u32(unsigned long long *state) {
    *state ^= *state >> 12; *state ^= *state << 25; *state ^= *state >> 27;
    return (*state * 0x2545F4914F6CDD1Dull) >> 32;
}

float random_f32(unsigned long long *state) { return (random_u32(state) >> 8) / 16777216.0f; }

int sample_topp(float* probs, int n, float topp, unsigned long long* rng) {
    float cutoff = (1.0f - topp) / (n - 1);
    float* prob_idx = malloc(n * sizeof(float));
    int* indices = malloc(n * sizeof(int));
    int n1 = 0;
    for (int i = 0; i < n; i++) {
        if (probs[i] >= cutoff) { prob_idx[n1] = probs[i]; indices[n1++] = i; }
    }
    for (int i = 0; i < n1-1; i++) {
        for (int j = i+1; j < n1; j++) {
            if (prob_idx[j] > prob_idx[i]) {
                float t = prob_idx[i]; prob_idx[i] = prob_idx[j]; prob_idx[j] = t;
                int ti = indices[i]; indices[i] = indices[j]; indices[j] = ti;
            }
        }
    }
    float cum = 0.0f; int last = n1 - 1;
    for (int i = 0; i < n1; i++) { cum += prob_idx[i]; if (cum > topp) { last = i; break; } }
    float r = random_f32(rng) * cum, cdf = 0.0f;
    for (int i = 0; i <= last; i++) { cdf += prob_idx[i]; if (r < cdf) { int res = indices[i]; free(prob_idx); free(indices); return res; } }
    int res = indices[last]; free(prob_idx); free(indices); return res;
}

// ----------------------------------------------------------------------------
// Load quantized model

void load_quantized_model(const char* path, Config* config, QuantizedWeights* weights) {
    FILE* f = fopen(path, "rb");
    if (!f) { fprintf(stderr, "Cannot open model: %s\n", path); exit(1); }
    
    fread(config, sizeof(Config), 1, f);
    weights->shared_weights = config->vocab_size > 0;
    config->vocab_size = abs(config->vocab_size);
    
    int n_layers = config->n_layers;
    int dim = config->dim;
    int hidden_dim = config->hidden_dim;
    int kv_dim = dim * config->n_kv_heads / config->n_heads;
    int vocab_size = config->vocab_size;
    
    printf("Model: dim=%d, hidden=%d, layers=%d, vocab=%d\n", dim, hidden_dim, n_layers, vocab_size);
    
    int n_weight_scales, n_act_scales;
    fread(&n_weight_scales, sizeof(int), 1, f);
    fread(&n_act_scales, sizeof(int), 1, f);
    
    weights->w_scales = (float**)malloc(n_layers * sizeof(float*));
    for (int l = 0; l < n_layers; l++) {
        weights->w_scales[l] = (float*)malloc(7 * sizeof(float));
        fread(weights->w_scales[l], sizeof(float), 7, f);
    }
    
    // Read embedding scale (used for classifier)
    fread(&weights->embedding_scale, sizeof(float), 1, f);
    
    weights->act_xb = (float*)malloc(n_layers * sizeof(float));
    weights->act_q = (float*)malloc(n_layers * sizeof(float));
    weights->act_k = (float*)malloc(n_layers * sizeof(float));
    weights->act_v = (float*)malloc(n_layers * sizeof(float));
    weights->act_xb_attn = (float*)malloc(n_layers * sizeof(float));
    weights->act_xb_ffn = (float*)malloc(n_layers * sizeof(float));
    weights->act_hb = (float*)malloc(n_layers * sizeof(float));
    weights->act_hb2 = (float*)malloc(n_layers * sizeof(float));
    weights->act_hb_silu = (float*)malloc(n_layers * sizeof(float));
    
    for (int l = 0; l < n_layers; l++) fread(&weights->act_xb[l], sizeof(float), 1, f);
    for (int l = 0; l < n_layers; l++) fread(&weights->act_q[l], sizeof(float), 1, f);
    for (int l = 0; l < n_layers; l++) fread(&weights->act_k[l], sizeof(float), 1, f);
    for (int l = 0; l < n_layers; l++) fread(&weights->act_v[l], sizeof(float), 1, f);
    for (int l = 0; l < n_layers; l++) fread(&weights->act_xb_attn[l], sizeof(float), 1, f);
    for (int l = 0; l < n_layers; l++) fread(&weights->act_xb_ffn[l], sizeof(float), 1, f);
    for (int l = 0; l < n_layers; l++) fread(&weights->act_hb[l], sizeof(float), 1, f);
    for (int l = 0; l < n_layers; l++) fread(&weights->act_hb2[l], sizeof(float), 1, f);
    for (int l = 0; l < n_layers; l++) fread(&weights->act_hb_silu[l], sizeof(float), 1, f);
    fread(&weights->act_x_final, sizeof(float), 1, f);
    fread(&weights->act_logits, sizeof(float), 1, f);
    
    weights->token_embedding_table = (float*)malloc(vocab_size * dim * sizeof(float));
    fread(weights->token_embedding_table, sizeof(float), vocab_size * dim, f);
    
    weights->rms_att_weight = (float*)malloc(n_layers * dim * sizeof(float));
    weights->rms_ffn_weight = (float*)malloc(n_layers * dim * sizeof(float));
    weights->rms_final_weight = (float*)malloc(dim * sizeof(float));
    fread(weights->rms_att_weight, sizeof(float), n_layers * dim, f);
    fread(weights->rms_ffn_weight, sizeof(float), n_layers * dim, f);
    fread(weights->rms_final_weight, sizeof(float), dim, f);
    
    weights->wq = (int8_t**)malloc(n_layers * sizeof(int8_t*));
    weights->wk = (int8_t**)malloc(n_layers * sizeof(int8_t*));
    weights->wv = (int8_t**)malloc(n_layers * sizeof(int8_t*));
    weights->wo = (int8_t**)malloc(n_layers * sizeof(int8_t*));
    weights->w1 = (int8_t**)malloc(n_layers * sizeof(int8_t*));
    weights->w2 = (int8_t**)malloc(n_layers * sizeof(int8_t*));
    weights->w3 = (int8_t**)malloc(n_layers * sizeof(int8_t*));
    
    for (int l = 0; l < n_layers; l++) {
        weights->wq[l] = (int8_t*)malloc(dim * dim);
        weights->wk[l] = (int8_t*)malloc(kv_dim * dim);
        weights->wv[l] = (int8_t*)malloc(kv_dim * dim);
        weights->wo[l] = (int8_t*)malloc(dim * dim);
        weights->w1[l] = (int8_t*)malloc(hidden_dim * dim);
        weights->w2[l] = (int8_t*)malloc(dim * hidden_dim);
        weights->w3[l] = (int8_t*)malloc(hidden_dim * dim);
        
        fread(weights->wq[l], 1, dim * dim, f);
        fread(weights->wk[l], 1, kv_dim * dim, f);
        fread(weights->wv[l], 1, kv_dim * dim, f);
        fread(weights->wo[l], 1, dim * dim, f);
        fread(weights->w1[l], 1, hidden_dim * dim, f);
        fread(weights->w2[l], 1, dim * hidden_dim, f);
        fread(weights->w3[l], 1, hidden_dim * dim, f);
    }
    
    // Read int8 embedding (used for classifier)
    weights->token_embedding_int8 = (int8_t*)malloc(vocab_size * dim);
    fread(weights->token_embedding_int8, 1, vocab_size * dim, f);
    
    fclose(f);
    printf("Model loaded (embedding_scale=%.6f)\n", weights->embedding_scale);
}

// ----------------------------------------------------------------------------
// Main

int main(int argc, char *argv[]) {
    if (argc < 2) {
        printf("Usage: %s <model_int8.bin> [options]\n", argv[0]);
        printf("  -t <float>  temperature (default 1.0)\n");
        printf("  -p <float>  top-p (default 0.9)\n");
        printf("  -n <int>    generation steps (default 32)\n");
        printf("  -i <string> input prompt\n");
        printf("  -z <string> tokenizer path\n");
        return 1;
    }
    
    char *model_path = argv[1];
    char *tokenizer_path = "tokenizer.bin";
    float temperature = 1.0f;
    float topp = 0.9f;
    int steps = 32;
    char *prompt = NULL;
    unsigned long long rng_seed = 0;
    
    for (int i = 2; i < argc; i += 2) {
        if (i + 1 >= argc) break;
        if (argv[i][0] == '-') {
            switch (argv[i][1]) {
                case 't': temperature = atof(argv[i+1]); break;
                case 'p': topp = atof(argv[i+1]); break;
                case 'n': steps = atoi(argv[i+1]); break;
                case 'i': prompt = argv[i+1]; break;
                case 'z': tokenizer_path = argv[i+1]; break;
                case 's': rng_seed = atoi(argv[i+1]); break;
            }
        }
    }
    if (rng_seed == 0) rng_seed = get_cycles();
    
    // Initialize Gemmini
    printf("Initializing Gemmini (DIM=%d)...\n", DIM);
    gemmini_flush(0);
    printf("Gemmini ready\n\n");
    
    // Load model
    Config config;
    QuantizedWeights weights;
    load_quantized_model(model_path, &config, &weights);
    
    // Allocate run state
    RunState state;
    int kv_dim = (config.dim * config.n_kv_heads) / config.n_heads;
    state.x = calloc(config.dim, sizeof(float));
    state.xb = calloc(config.dim, sizeof(float));
    state.xb2 = calloc(config.dim, sizeof(float));
    state.hb = calloc(config.hidden_dim, sizeof(float));
    state.hb2 = calloc(config.hidden_dim, sizeof(float));
    state.q = calloc(config.dim, sizeof(float));
    state.att = calloc(config.n_heads * config.seq_len, sizeof(float));
    state.logits = calloc(config.vocab_size, sizeof(float));
    state.key_cache = calloc(config.n_layers * config.seq_len * kv_dim, sizeof(float));
    state.value_cache = calloc(config.n_layers * config.seq_len * kv_dim, sizeof(float));
    
    // Load tokenizer
    Tokenizer tokenizer;
    build_tokenizer(&tokenizer, tokenizer_path, config.vocab_size);
    
    // Encode prompt
    int *prompt_tokens = malloc((strlen(prompt ? prompt : "") + 3) * sizeof(int));
    int num_prompt_tokens = 0;
    if (prompt) {
        encode(&tokenizer, prompt, 1, 0, prompt_tokens, &num_prompt_tokens);
    } else {
        prompt_tokens[0] = 1;
        num_prompt_tokens = 1;
    }
    
    // Generate
    printf("\n--- Generation (Gemmini Int8) ---\n");
    
    uint64_t start_time = get_cycles();
    
    int token = prompt_tokens[0];
    int next, pos = 0;
    
    while (pos < steps) {
        float* logits = forward(token, pos, &config, &weights, &state);
        
        if (pos < num_prompt_tokens - 1) {
            next = prompt_tokens[pos + 1];
        } else {
            if (temperature == 0.0f) {
                PROFILE_START();
                next = sample_argmax(logits, config.vocab_size);
                PROFILE_END(sampling);
            } else {
                // Temperature scaling
                PROFILE_START();
                for (int q = 0; q < config.vocab_size; q++) logits[q] /= temperature;
                PROFILE_END(temp_scaling);
                
                // Softmax on 32000-dim logits
                PROFILE_START();
                softmax(logits, config.vocab_size);
                PROFILE_END(softmax_logits);
                
                // Sampling
                PROFILE_START();
                next = (topp <= 0 || topp >= 1) ? 
                       sample_argmax(logits, config.vocab_size) :
                       sample_topp(logits, config.vocab_size, topp, &rng_seed);
                PROFILE_END(sampling);
            }
        }
        
        // Decode and print
        PROFILE_START();
        char *piece = decode(&tokenizer, token, next);
        printf("%s", piece);
        fflush(stdout);
        PROFILE_END(decode_print);
        
        token = next;
        pos++;
        
        if (next == 1 || next == 2) break;
    }
    
    uint64_t end_time = get_cycles();
    
    uint64_t total_time = end_time - start_time;
    
    printf("\n\n");
    printf("================================================================================\n");
    printf("                           PERFORMANCE PROFILING REPORT\n");
    printf("================================================================================\n\n");
    
    printf("--- Basic Info ---\n");
    printf("Tokens generated:     %d\n", pos);
    printf("Total cycles:         %lu\n", total_time);
    printf("Cycles/token:         %lu\n", total_time / (pos > 0 ? pos : 1));
    printf("Gemmini matmul calls: %d\n", gemmini_calls);
    printf("CPU matmul calls:     %d\n", cpu_calls);
    printf("\n");
    
#if ENABLE_PROFILING
    // Compute total time and percentages
    uint64_t total_forward = g_profile.embedding + g_profile.rmsnorm_att + 
        g_profile.rmsnorm_ffn + g_profile.rmsnorm_final + g_profile.qkv_proj +
        g_profile.rope + g_profile.attention + g_profile.wo_proj +
        g_profile.ffn_w1w3 + g_profile.ffn_silu + g_profile.ffn_w2 +
        g_profile.residual + g_profile.classifier;
    
    uint64_t total_sampling = g_profile.temp_scaling + g_profile.softmax_logits + 
        g_profile.sampling + g_profile.decode_print;
    
    uint64_t total_profiled = total_forward + total_sampling;
    
    uint64_t total_matmul = g_profile.qkv_proj + g_profile.wo_proj + 
        g_profile.ffn_w1w3 + g_profile.ffn_w2;
    
    uint64_t total_cpu_ops = g_profile.embedding + g_profile.rmsnorm_att + 
        g_profile.rmsnorm_ffn + g_profile.rmsnorm_final + g_profile.rope + 
        g_profile.attention + g_profile.ffn_silu + g_profile.residual + 
        g_profile.classifier + g_profile.temp_scaling + g_profile.softmax_logits +
        g_profile.sampling + g_profile.decode_print;
    
    #define PERCENT(x) ((double)(x) * 100.0 / (total_profiled > 0 ? total_profiled : 1))
    #define CYCLES_PER_TOK(x) ((x) / (g_profile.total_tokens > 0 ? g_profile.total_tokens : 1))
    
    printf("--- forward() Internal Time Distribution ---\n");
    printf("%-20s %12s %8s %12s\n", "Stage", "Cycles", "Pct%", "Cycles/tok");
    printf("-------------------- ------------ -------- ------------\n");
    printf("%-20s %12lu %7.2f%% %12lu\n", "Embedding", g_profile.embedding, PERCENT(g_profile.embedding), CYCLES_PER_TOK(g_profile.embedding));
    printf("%-20s %12lu %7.2f%% %12lu\n", "RMSNorm (att)", g_profile.rmsnorm_att, PERCENT(g_profile.rmsnorm_att), CYCLES_PER_TOK(g_profile.rmsnorm_att));
    printf("%-20s %12lu %7.2f%% %12lu\n", "QKV Projection", g_profile.qkv_proj, PERCENT(g_profile.qkv_proj), CYCLES_PER_TOK(g_profile.qkv_proj));
    printf("%-20s %12lu %7.2f%% %12lu\n", "RoPE", g_profile.rope, PERCENT(g_profile.rope), CYCLES_PER_TOK(g_profile.rope));
    printf("%-20s %12lu %7.2f%% %12lu\n", "Attention (CPU)", g_profile.attention, PERCENT(g_profile.attention), CYCLES_PER_TOK(g_profile.attention));
    printf("%-20s %12lu %7.2f%% %12lu\n", "WO Projection", g_profile.wo_proj, PERCENT(g_profile.wo_proj), CYCLES_PER_TOK(g_profile.wo_proj));
    printf("%-20s %12lu %7.2f%% %12lu\n", "RMSNorm (ffn)", g_profile.rmsnorm_ffn, PERCENT(g_profile.rmsnorm_ffn), CYCLES_PER_TOK(g_profile.rmsnorm_ffn));
    printf("%-20s %12lu %7.2f%% %12lu\n", "FFN W1+W3", g_profile.ffn_w1w3, PERCENT(g_profile.ffn_w1w3), CYCLES_PER_TOK(g_profile.ffn_w1w3));
    printf("%-20s %12lu %7.2f%% %12lu\n", "SiLU", g_profile.ffn_silu, PERCENT(g_profile.ffn_silu), CYCLES_PER_TOK(g_profile.ffn_silu));
    printf("%-20s %12lu %7.2f%% %12lu\n", "FFN W2", g_profile.ffn_w2, PERCENT(g_profile.ffn_w2), CYCLES_PER_TOK(g_profile.ffn_w2));
    printf("%-20s %12lu %7.2f%% %12lu\n", "RMSNorm (final)", g_profile.rmsnorm_final, PERCENT(g_profile.rmsnorm_final), CYCLES_PER_TOK(g_profile.rmsnorm_final));
    printf("%-20s %12lu %7.2f%% %12lu\n", "Residual", g_profile.residual, PERCENT(g_profile.residual), CYCLES_PER_TOK(g_profile.residual));
    printf("%-20s %12lu %7.2f%% %12lu\n", "Classifier (CPU)", g_profile.classifier, PERCENT(g_profile.classifier), CYCLES_PER_TOK(g_profile.classifier));
    printf("-------------------- ------------ -------- ------------\n");
    printf("%-20s %12lu %7.2f%%\n", "forward() subtotal", total_forward, PERCENT(total_forward));
    printf("\n");
    
    printf("--- Sampling Stage Time Distribution (outside forward) ---\n");
    printf("%-20s %12s %8s %12s\n", "Stage", "Cycles", "Pct%", "Cycles/tok");
    printf("-------------------- ------------ -------- ------------\n");
    printf("%-20s %12lu %7.2f%% %12lu\n", "Temp scaling", g_profile.temp_scaling, PERCENT(g_profile.temp_scaling), CYCLES_PER_TOK(g_profile.temp_scaling));
    printf("%-20s %12lu %7.2f%% %12lu\n", "Softmax (32000!)", g_profile.softmax_logits, PERCENT(g_profile.softmax_logits), CYCLES_PER_TOK(g_profile.softmax_logits));
    printf("%-20s %12lu %7.2f%% %12lu\n", "Sampling", g_profile.sampling, PERCENT(g_profile.sampling), CYCLES_PER_TOK(g_profile.sampling));
    printf("%-20s %12lu %7.2f%% %12lu\n", "Decode+Print", g_profile.decode_print, PERCENT(g_profile.decode_print), CYCLES_PER_TOK(g_profile.decode_print));
    printf("-------------------- ------------ -------- ------------\n");
    printf("%-20s %12lu %7.2f%%\n", "Sampling subtotal", total_sampling, PERCENT(total_sampling));
    printf("\n");
    
    printf("--- Gemmini Matmul Internal Breakdown ---\n");
    uint64_t total_matmul_internal = g_profile.matmul_quantize + g_profile.matmul_gemmini + g_profile.matmul_dequantize;
    printf("%-20s %12lu %7.2f%% (of matmul)\n", "Input quantize", g_profile.matmul_quantize,
           (double)g_profile.matmul_quantize * 100.0 / (total_matmul_internal > 0 ? total_matmul_internal : 1));
    printf("%-20s %12lu %7.2f%% (of matmul)\n", "Gemmini compute", g_profile.matmul_gemmini,
           (double)g_profile.matmul_gemmini * 100.0 / (total_matmul_internal > 0 ? total_matmul_internal : 1));
    printf("%-20s %12lu %7.2f%% (of matmul)\n", "Output dequantize", g_profile.matmul_dequantize,
           (double)g_profile.matmul_dequantize * 100.0 / (total_matmul_internal > 0 ? total_matmul_internal : 1));
    printf("\n");
    
    printf("--- Summary ---\n");
    printf("%-25s %12lu %7.2f%%\n", "Gemmini matmul total", total_matmul, PERCENT(total_matmul));
    printf("%-25s %12lu %7.2f%%\n", "CPU compute total", total_cpu_ops, PERCENT(total_cpu_ops));
    printf("%-25s %12lu %7.2f%%\n", "TOTAL (profiled)", total_profiled, 100.0);
    printf("%-25s %12lu\n", "Overhead (untracked)", total_time > total_profiled ? total_time - total_profiled : 0);
    printf("\n");
    
    // Bottleneck analysis
    printf("--- Bottleneck Analysis ---\n");

    // Find the top bottlenecks
    const char* bn_names[10] = {
        "QKV Projection", "Attention (CPU)", "FFN W1+W3", "FFN W2",
        "WO Projection", "Classifier (CPU)", "RoPE", "SiLU",
        "Softmax (32000)", "Temp scaling"
    };
    uint64_t bn_times[10] = {
        g_profile.qkv_proj, g_profile.attention, g_profile.ffn_w1w3, g_profile.ffn_w2,
        g_profile.wo_proj, g_profile.classifier, g_profile.rope, g_profile.ffn_silu,
        g_profile.softmax_logits, g_profile.temp_scaling
    };
    int n_bottlenecks = 10;
    
    // Simple sort (bubble sort)
    for (int i = 0; i < n_bottlenecks - 1; i++) {
        for (int j = i + 1; j < n_bottlenecks; j++) {
            if (bn_times[j] > bn_times[i]) {
                uint64_t tmp_t = bn_times[i]; bn_times[i] = bn_times[j]; bn_times[j] = tmp_t;
                const char* tmp_n = bn_names[i]; bn_names[i] = bn_names[j]; bn_names[j] = tmp_n;
            }
        }
    }
    
    printf("Top 5 bottlenecks:\n");
    for (int i = 0; i < 5 && i < n_bottlenecks; i++) {
        printf("  %d. %-20s %7.2f%%\n", i+1, bn_names[i], PERCENT(bn_times[i]));
    }
    printf("\n");
    
    // Optimization suggestions
    printf("--- Optimization Suggestions ---\n");
    if (PERCENT(g_profile.classifier) > 15) {
        printf("* Classifier takes %.1f%%, consider quantizing embedding or accelerating with Gemmini\n", PERCENT(g_profile.classifier));
    }
    if (PERCENT(g_profile.softmax_logits) > 10) {
        printf("* Softmax (32000) takes %.1f%%, consider LUT-based exp approximation or top-k pruning\n", PERCENT(g_profile.softmax_logits));
    }
    if (PERCENT(g_profile.temp_scaling) > 5) {
        printf("* Temp scaling takes %.1f%%, can be merged with classifier\n", PERCENT(g_profile.temp_scaling));
    }
    if (PERCENT(g_profile.attention) > 20) {
        printf("* Attention takes %.1f%%, consider accelerating QK^T with Gemmini\n", PERCENT(g_profile.attention));
    }
    double quant_overhead = (double)(g_profile.matmul_quantize + g_profile.matmul_dequantize) * 100.0 / 
                            (total_matmul_internal > 0 ? total_matmul_internal : 1);
    if (quant_overhead > 30) {
        printf("* Quantize/dequantize overhead %.1f%%, consider reducing intermediate conversions or fused kernel\n", quant_overhead);
    }
    if (PERCENT(g_profile.rope) > 5) {
        printf("* RoPE takes %.1f%%, consider precomputing sin/cos table\n", PERCENT(g_profile.rope));
    }
    
    printf("\n================================================================================\n");
#endif
    
    return 0;
}
